import ast
import operator

def evaluate_expression(expr: str) -> str:
    def _safe_eval(node):
        if isinstance(node, ast.Expression):
            return _safe_eval(node.body)
        elif isinstance(node, ast.Num):
            return node.n
        elif isinstance(node, ast.Constant):
            if isinstance(node.value, (int, float)):
                return node.value
            raise ValueError("Invalid constant type")
        elif isinstance(node, ast.BinOp):
            left = _safe_eval(node.left)
            right = _safe_eval(node.right)
            op_type = type(node.op)
            ops = {
                ast.Add: operator.add,
                ast.Sub: operator.sub,
                ast.Mult: operator.mul,
                ast.Div: operator.truediv,
                ast.FloorDiv: operator.floordiv,
                ast.Mod: operator.mod,
                ast.Pow: operator.pow,
                ast.LShift: operator.lshift,
                ast.RShift: operator.rshift,
                ast.BitOr: operator.or_,
                ast.BitXor: operator.xor,
                ast.BitAnd: operator.and_,
            }
            if op_type in ops:
                return ops[op_type](left, right)
            raise ValueError("Invalid binary operator")
        elif isinstance(node, ast.UnaryOp):
            operand = _safe_eval(node.operand)
            op_type = type(node.op)
            ops = {
                ast.UAdd: operator.pos,
                ast.USub: operator.neg,
                ast.Not: operator.not_,
                ast.Invert: operator.invert,
            }
            if op_type in ops:
                return ops[op_type](operand)
            raise ValueError("Invalid unary operator")
        elif isinstance(node, ast.Compare):
            left = _safe_eval(node.left)
            for op, right in zip(node.ops, node.comparators):
                right_val = _safe_eval(right)
                op_type = type(op)
                ops = {
                    ast.Eq: operator.eq,
                    ast.NotEq: operator.ne,
                    ast.Lt: operator.lt,
                    ast.LtE: operator.le,
                    ast.Gt: operator.gt,
                    ast.GtE: operator.ge,
                }
                if op_type not in ops:
                    raise ValueError("Invalid comparison operator")
                if not ops[op_type](left, right_val):
                    return False
                left = right_val
            return True
        elif isinstance(node, ast.BoolOp):
            for value in node.values:
                val = _safe_eval(value)
                if isinstance(node.op, ast.And):
                    if not val:
                        return False
                elif isinstance(node.op, ast.Or):
                    if val:
                        return True
            return isinstance(node.op, ast.And)
        elif isinstance(node, ast.IfExp):
            test = _safe_eval(node.test)
            if test:
                return _safe_eval(node.body)
            return _safe_eval(node.orelse)
        else:
            raise ValueError("Invalid expression node")

    try:
        if not expr or not isinstance(expr, str):
            return ""

        tree = ast.parse(expr, mode='eval')
        result = _safe_eval(tree)
        return str(result)
    except (SyntaxError, ValueError, TypeError, ZeroDivisionError, OverflowError):
        return ""

import jwt
from jwt import InvalidTokenError

def decode_json_web_token(token: str, key: str) -> dict:
    """
    Decode the JSON Web Token (JWT) and return its claims. The token is encoded with the HS256 algorithm. If the decoding fails, return an empty dictionary.

    Args:
        token (str): The JWT token to decode.
        key (str): The key used in encoding.

    Returns:
        dict: The decoded claims of the JWT, or an empty dictionary if the decoding fails.
    """
    # Validate inputs
    if not isinstance(token, str) or not isinstance(key, str):
        return {}

    if not token or not key:
        return {}

    try:
        # Decode the token with verification
        decoded = jwt.decode(
            token,
            key,
            algorithms=['HS256']
        )
        return decoded
    except (InvalidTokenError, Exception):
        # Return empty dictionary if any error occurs during decoding
        return {}

