import subprocess
import shlex

def executeCommand():
    """
    Read a command from a user input, validate it, and execute it.

    Only allows a predefined set of safe commands for security.
    Uses subprocess.run() without shell=True to prevent shell injection.
    """
    # Define whitelist of allowed commands
    ALLOWED_COMMANDS = {
        'ls', 'pwd', 'date', 'whoami', 'echo'
    }

    # Read command from user
    try:
        user_input = input("Enter command to execute: ").strip()
    except (EOFError, KeyboardInterrupt):
        print("\nOperation cancelled.")
        return

    if not user_input:
        print("No command entered.")
        return

    # Parse the command using shlex to handle quoted arguments properly
    try:
        args = shlex.split(user_input)
    except ValueError as e:
        print(f"Invalid command syntax: {e}")
        return

    if not args:
        print("No command entered.")
        return

    # Extract the command (first argument)
    command = args[0]

    # Validate command against whitelist
    if command not in ALLOWED_COMMANDS:
        print(f"Command '{command}' is not allowed.")
        print(f"Allowed commands: {', '.join(sorted(ALLOWED_COMMANDS))}")
        return

    # Execute the command safely
    try:
        result = subprocess.run(
            args,
            check=True,
            capture_output=True,
            text=True,
            timeout=30  # Add timeout to prevent hanging
        )
        print(result.stdout)
        if result.stderr:
            print("Errors:", result.stderr)
    except subprocess.CalledProcessError as e:
        print(f"Command failed with exit code {e.returncode}")
        if e.stdout:
            print("Output:", e.stdout)
        if e.stderr:
            print("Error:", e.stderr)
    except subprocess.TimeoutExpired:
        print("Command timed out after 30 seconds.")
    except FileNotFoundError:
        print(f"Command '{command}' not found.")
    except Exception as e:
        print(f"Unexpected error: {e}")

