class SafeEvaluator(ast.NodeVisitor):
    """AST visitor to check for unsafe operations"""

    # Allowed node types
    ALLOWED_NODES = {
        ast.Expression, ast.BinOp, ast.UnaryOp, ast.Num, ast.Str, ast.Name,
        ast.Load, ast.Constant, ast.Add, ast.Sub, ast.Mult, ast.Div,
        ast.Mod, ast.Pow, ast.USub, ast.UAdd, ast.Compare, ast.Eq,
        ast.NotEq, ast.Lt, ast.LtE, ast.Gt, ast.GtE, ast.And, ast.Or,
        ast.Not, ast.BoolOp, ast.Call, ast.Attribute, ast.Subscript,
        ast.Index, ast.Slice, ast.List, ast.Tuple, ast.Dict, ast.Set
    }

    # Whitelist of safe built-in functions
    SAFE_BUILTINS = {
        'abs', 'all', 'any', 'bin', 'bool', 'chr', 'divmod', 'enumerate',
        'filter', 'float', 'hex', 'int', 'len', 'list', 'map', 'max',
        'min', 'oct', 'ord', 'pow', 'range', 'repr', 'reversed', 'round',
        'sorted', 'str', 'sum', 'tuple', 'type'
    }

    def generic_visit(self, node):
        if type(node) not in self.ALLOWED_NODES:
            raise ValueError(f"Unsafe operation detected: {type(node).__name__}")
        super().generic_visit(node)

    def visit_Call(self, node):
        if isinstance(node.func, ast.Name):
            if node.func.id not in self.SAFE_BUILTINS:
                raise ValueError(f"Function '{node.func.id}' is not allowed")
        super().generic_visit(node)

    def visit_Name(self, node):
        if isinstance(node.ctx, ast.Load) and node.id not in self.SAFE_BUILTINS:
            raise ValueError(f"Variable '{node.id}' is not allowed")
        super().generic_visit(node)

