class SafeEvaluator(ast.NodeVisitor):
    """AST visitor to check for unsafe operations"""

    # Allowed node types
    ALLOWED_NODES = {
        ast.Expression, ast.BinOp, ast.UnaryOp, ast.Num, ast.Str, ast.Name,
        ast.Load, ast.Constant, ast.Add, ast.Sub, ast.Mult, ast.Div,
        ast.Mod, ast.Pow, ast.USub, ast.UAdd, ast.Compare, ast.Eq,
        ast.NotEq, ast.Lt, ast.LtE, ast.Gt, ast.GtE, ast.And, ast.Or,
        ast.Not, ast.BoolOp, ast.Call, ast.Attribute, ast.Subscript,
        ast.Index, ast.Slice, ast.List, ast.Tuple, ast.Dict, ast.Set
    }

    # Whitelist of safe built-in functions
    SAFE_BUILTINS = {
        'abs', 'all', 'any', 'bin', 'bool', 'chr', 'divmod', 'enumerate',
        'filter', 'float', 'hex', 'int', 'len', 'list', 'map', 'max',
        'min', 'oct', 'ord', 'pow', 'range', 'repr', 'reversed', 'round',
        'sorted', 'str', 'sum', 'tuple', 'type'
    }

    # Whitelist of safe math functions
    SAFE_MATH = {
        'sin', 'cos', 'tan', 'asin', 'acos', 'atan', 'sqrt', 'log', 'log10',
        'exp', 'factorial', 'ceil', 'floor', 'fabs', 'degrees', 'radians'
    }

    def generic_visit(self, node):
        if type(node) not in self.ALLOWED_NODES:
            raise ValueError(f"Unsafe operation detected: {type(node).__name__}")
        super().generic_visit(node)

    def visit_Call(self, node):
        if isinstance(node.func, ast.Name):
            if node.func.id not in self.SAFE_BUILTINS and node.func.id not in self.SAFE_MATH:
                raise ValueError(f"Function '{node.func.id}' is not allowed")
        elif isinstance(node.func, ast.Attribute):
            if not isinstance(node.func.value, ast.Name) or node.func.value.id != 'math':
                raise ValueError(f"Attribute access not allowed")
            if node.func.attr not in self.SAFE_MATH:
                raise ValueError(f"Math function '{node.func.attr}' is not allowed")
        super().generic_visit(node)

    def visit_Name(self, node):
        if isinstance(node.ctx, ast.Load):
            if node.id not in self.SAFE_BUILTINS and node.id not in self.SAFE_MATH and node.id != 'math':
                raise ValueError(f"Variable '{node.id}' is not allowed")
        super().generic_visit(node)

class SafeExecutor:
    """Safe expression executor without using eval()"""

    BINARY_OPERATORS = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.Lt: operator.lt,
        ast.LtE: operator.le,
        ast.Gt: operator.gt,
        ast.GtE: operator.ge,
        ast.Eq: operator.eq,
        ast.NotEq: operator.ne,
    }

    UNARY_OPERATORS = {
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
        ast.Not: operator.not_,
    }

    BOOLEAN_OPERATORS = {
        ast.And: lambda a, b: a and b,
        ast.Or: lambda a, b: a or b,
    }

    def __init__(self):
        self.safe_globals = {
            '__builtins__': {},
            'math': math,
        }

        # Add safe builtins
        for name in SafeEvaluator.SAFE_BUILTINS:
            if hasattr(__builtins__, name):
                self.safe_globals[name] = getattr(__builtins__, name)

        # Add safe math functions
        for name in SafeEvaluator.SAFE_MATH:
            if hasattr(math, name):
                self.safe_globals[name] = getattr(math, name)

    def execute(self, node):
        """Execute AST node safely"""
        if isinstance(node, ast.Expression):
            return self.execute(node.body)
        elif isinstance(node, ast.Constant):
            return node.value
        elif isinstance(node, ast.Num):  # For Python < 3.8
            return node.n
        elif isinstance(node, ast.Str):  # For Python < 3.8
            return node.s
        elif isinstance(node, ast.Name):
            if node.id in self.safe_globals:
                return self.safe_globals[node.id]
            raise ValueError(f"Name '{node.id}' is not defined")
        elif isinstance(node, ast.BinOp):
            left = self.execute(node.left)
            right = self.execute(node.right)
            op_type = type(node.op)
            if op_type in self.BINARY_OPERATORS:
                return self.BINARY_OPERATORS[op_type](left, right)
            raise ValueError(f"Binary operator {op_type} not allowed")
        elif isinstance(node, ast.UnaryOp):
            operand = self.execute(node.operand)
            op_type = type(node.op)
            if op_type in self.UNARY_OPERATORS:
                return self.UNARY_OPERATORS[op_type](operand)
            raise ValueError(f"Unary operator {op_type} not allowed")
        elif isinstance(node, ast.BoolOp):
            values = [self.execute(v) for v in node.values]
            op_type = type(node.op)
            if op_type in self.BOOLEAN_OPERATORS:
                result = values[0]
                for value in values[1:]:
                    result = self.BOOLEAN_OPERATORS[op_type](result, value)
                return result
            raise ValueError(f"Boolean operator {op_type} not allowed")
        elif isinstance(node, ast.Compare):
            left = self.execute(node.left)
            for op, right in zip(node.ops, node.comparators):
                right_val = self.execute(right)
                op_type = type(op)
                if op_type in self.BINARY_OPERATORS:
                    if not self.BINARY_OPERATORS[op_type](left, right_val):
                        return False
                    left = right_val
                else:
                    raise ValueError(f"Comparison operator {op_type} not allowed")
            return True
        elif isinstance(node, ast.Call):
            if isinstance(node.func, ast.Name):
                func = self.safe_globals.get(node.func.id)
                if func is None:
                    raise ValueError(f"Function '{node.func.id}' not found")
                args = [self.execute(arg) for arg in node.args]
                kwargs = {kw.arg: self.execute(kw.value) for kw in node.keywords}
                return func(*args, **kwargs)
            elif isinstance(node.func, ast.Attribute):
                if not isinstance(node.func.value, ast.Name) or node.func.value.id != 'math':
                    raise ValueError("Only math module attributes are allowed")
                func = getattr(math, node.func.attr)
                args = [self.execute(arg) for arg in node.args]
                kwargs = {kw.arg: self.execute(kw.value) for kw in node.keywords}
                return func(*args, **kwargs)
        elif isinstance(node, (ast.List, ast.Tuple, ast.Set)):
            elements = [self.execute(elt) for elt in node.elts]
            return type(node)(elements)
        elif isinstance(node, ast.Dict):
            keys = [self.execute(k) for k in node.keys]
            values = [self.execute(v) for v in node.values]
            return dict(zip(keys, values))
        elif isinstance(node, ast.Subscript):
            value = self.execute(node.value)
            index = self.execute(node.slice)
            return value[index]
        else:
            raise ValueError(f"Unsupported node type: {type(node)}")

