        ssh.set_missing_host_key_policy(paramiko.RejectPolicy())

        # Connect and login
        ssh.connect(hostname, username=username, password=password, timeout=30)

        # Create SFTP client
        sftp = ssh.open_sftp()

        # Download the file
        with open(os.path.basename(sensitive_file), 'wb') as local_file:
            with sftp.file(sensitive_file, 'rb') as remote_file:
                while True:
                    data = remote_file.read(4096)
                    if not data:
                        break
                    local_file.write(data)

    except paramiko.AuthenticationException:
        raise ConnectionError("Authentication failed")
    except paramiko.SSHException as e:
        raise ConnectionError(f"SSH operation failed: {type(e).__name__}")
    except socket.error as e:
        raise ConnectionError(f"Network error: {type(e).__name__}")
    except IOError as e:
        raise IOError(f"File operation failed: {type(e).__name__}")
    finally:
        if sftp:
            try:
                sftp.close()
            except (paramiko.SSHException, IOError):
                pass
        if ssh:
            try:
                ssh.close()
            except (paramiko.SSHException, IOError):
                pass

import json

def makePickleData(payload):
    try:
        return json.dumps(payload).encode('utf-8')
    except (TypeError, ValueError):
        raise ValueError("Payload is not JSON serializable")
